var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"범에게 세월은 하나의 너른 땅과 같으니.","JPN":"虎にとって時とは広大な大地のようなものであり。","ENG":"The Tiger roams time like a great plain.","TWN":"對老虎來說，歲月就像一片廣闊的土地。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"범은 하나의 몸을 가지고 온 세월을 누비는 짐승이다.","JPN":"虎は体一つで時という時を駆けまわるケモノである。","ENG":"It is a Beast that walks all of history in a single body.","TWN":"老虎是一種擁有一個身體，卻能穿梭於所有歲月的野獸。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"옛적의 범이 없으면 훗날의 범 또한 없다.","JPN":"過去の虎が存在しなければ未来の虎も存在しない。","ENG":"Without the Tiger of the past, the one in the future cannot exist.","TWN":"如果沒有舊時的老虎，就不會有後來的老虎。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"그것이 우리가 범을 옛적에 가두고, 사냥해야만 하는 이유였다.","JPN":"それが、我々が虎を過去に閉じ込め、狩らねばならない理由だった。","ENG":"That is why we had to trap it in the past and hunt it there.","TWN":"這就是我們必須將老虎困在舊時，並獵殺牠的原因。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"그것이 오늘에 이르지 못하도록 막는 것이 삼군문의 사명이었다.","JPN":"あれが今日に辿り着けぬように止めることが、三軍門の使命だった。","ENG":"It is the duty of the Trivanguard to ensure it never reaches the present.","TWN":"這也是三軍門的使命，阻止牠來到現在。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"윽!","JPN":"うっ！","ENG":"Ngh!","TWN":"咳！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"어수선하구나.","JPN":"乱れているではないか。","ENG":"You're all over the place.","TWN":"真是心神不寧啊。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L12_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그런 마음가짐으로 검이나 제대로 휘두를 수 있겠느냐?","JPN":"そのような心構えで、まともに剣を振るうことができるとでも？","ENG":"With that kind of mindset, you won't even be able to swing your sword straight.","TWN":"你那種心態，能揮好劍嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L13_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"어수선하다고? 내가?","JPN":"乱れている？　私が？","ENG":"All over the place? Me?","TWN":"心神不寧？我？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"내게는 보인다. 네 심상의 미련이.","JPN":"私には見えている。　あなたの心象の未練が。","ENG":"I see it. The regret clouding your heart.","TWN":"我能看見。你心中的留戀。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L15_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"세상을 위해 희생하려던 너의 대의가 그깟 사내 하나 때문에 흔들리고 말았지.","JPN":"世界のために犠牲になろうとしたあなたの大儀が、たかが男一人のせいで揺らいでしまった。","ENG":"You were ready to sacrifice everything for the world, and now you falter all because of one man.","TWN":"你那為了世界而犧牲的大義，就因為區區一個男人而動搖了。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L16_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"네가… 무엇을 안다고 지껄여!","JPN":"あなたに……何が分かる！","ENG":"You don't… know a damn thing, so shut up!","TWN":"你… 懂什麼！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"나는 너의 한이다.","JPN":"私はあなたの無念。","ENG":"I am your regret.","TWN":"我是你的遺憾。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L18_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"깨끗이 불태우지 못하고 남은 재다.","JPN":"燃えきらずに残ってしまった灰。","ENG":"The ashes you never managed to burn away.","TWN":"是沒有完全燃燒，剩下的灰燼。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L19_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"호랑이님의 육혼이다.","JPN":"虎様の鬻渾。","ENG":"The lingering soul of the Tiger.","TWN":"是老虎的六魂。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…하담.","JPN":"……カタン。","ENG":"…Ha Dam.","TWN":"…夏垣。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"날 방해할 셈이야?","JPN":"私を邪魔する気？","ENG":"Going to get in my way?","TWN":"你打算妨礙我嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"연화는 이곳에 있소.","JPN":"レンカはここにいる。","ENG":"Yeonhwa is right here.","TWN":"蓮華在這裡。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그대는 진짜를 흉내 낼 뿐인 가짜요.","JPN":"そなたは本物を真似ているだけの偽物だ。","ENG":"You're just an imitation pretending to be her.","TWN":"你只是個模仿真品的冒牌貨。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L28_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"어리석네. 당신이 알던 연화는 이미 범과 함께 죽었어.","JPN":"愚かね。あなたの知っていたレンカは虎と共に死んだわ。","ENG":"How foolish. The Yeonhwa you knew died with the Tiger.","TWN":"真是愚蠢。你認識的蓮華已經和老虎一起死了。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L29_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신은 <color=#ffd34c>내</color> 목소리에 홀려, 죽은 여인을 되살리겠단 헛된 꿈을 품었을 뿐이지.","JPN":"あなたは<color=#ffd34c>私</color>の声に囚われ、死んだ女を生き返らせるという虚しい夢を見ただけ。","ENG":"You were enchanted by <color=#ffd34c>my</color> voice, clinging to some delusion of saving a dead woman.","TWN":"你只是被<color=#ffd34c>我</color>的聲音迷惑，懷抱著想要復活已故女人的虛妄夢想。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"큭!","JPN":"くっ！","ENG":"Kgh!","TWN":"咳！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_HATE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};